previewCss:
.darma-loader-darma-custom-225 {
  color: var(--loader-color, #e11d48);
  width: 90px;
  height: 14px;
  --c: 50%,currentColor 90deg,#0000 0;
  background: 
    conic-gradient(from   45deg at calc(100% - 7px) var(--c)),
    conic-gradient(from -135deg at             7px  var(--c));
  background-position: calc(100%/3) 0;
  background-size: calc(100%/4) 100%;
  animation: darma-loader-darma-custom-225-l6 0.5s infinite linear;
}
@keyframes darma-loader-darma-custom-225-l6 {
    100% {background-position: 0 0}
}

